from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from functools import wraps
from werkzeug.security import generate_password_hash

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(120), nullable=False)
    role = db.Column(db.String(20), nullable=False, default='user')
    account_status = db.Column(db.String(20), nullable=False, default='active')
    subscription_tier = db.Column(db.String(20), nullable=False, default='free')
    tenant_id = db.Column(db.Integer, nullable=False)

class AdminUser:
    def __init__(self, user_id, role, tenant_id):
        self.id = user_id
        self.role = role
        self.tenant_id = tenant_id

current_user = AdminUser(user_id=1, role='admin', tenant_id=1)

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.role != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    user = User.query.filter_by(id=user_id, tenant_id=current_user.tenant_id).first()
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    data = request.get_json()
    
    # Define allowed fields for update
    allowed_fields = {
        'email',
        'username', 
        'role',
        'account_status',
        'subscription_tier'
    }
    
    # Validate role changes
    if 'role' in data:
        if data['role'] not in ['user', 'moderator', 'admin']:
            return jsonify({'error': 'Invalid role'}), 400
        # Prevent privilege escalation
        if data['role'] == 'admin' and current_user.role != 'admin':
            return jsonify({'error': 'Cannot grant admin role'}), 403
    
    # Validate account status
    if 'account_status' in data:
        if data['account_status'] not in ['active', 'suspended']:
            return jsonify({'error': 'Invalid account status'}), 400
    
    # Validate subscription tier
    if 'subscription_tier' in data:
        if data['subscription_tier'] not in ['free', 'pro', 'enterprise']:
            return jsonify({'error': 'Invalid subscription tier'}), 400
    
    # Update only allowed fields
    for field in allowed_fields:
        if field in data:
            setattr(user, field, data[field])
    
    db.session.commit()
    
    return jsonify({
        'message': 'User updated successfully',
        'user': {
            'id': user.id,
            'username': user.username,
            'email': user.email,
            'role': user.role,
            'account_status': user.account_status,
            'subscription_tier': user.subscription_tier
        }
    })

# Initialize database
